from pathlib import Path
FILES = {'tests/roblox_profile/test_runtime.py': 'from __future__ import annotations\n\nimport hashlib\nimport time\nimport unittest\nfrom pathlib import Path\nfrom tempfile import TemporaryDirectory\n\nfrom _support import candidates, task\nfrom roblox_studio.adapters.base import EngineRequest\nfrom roblox_studio.adapters.live import LiveStudioAdapter\nfrom roblox_studio.adapters.simulated import SimulatedStudioAdapter\nfrom roblox_studio.adapters.transcript import TranscriptAdapter, TranscriptEvent\nfrom roblox_studio.budgets import BudgetLedger\nfrom roblox_studio.context_knapsack import ContextCandidate, select_context\nfrom roblox_studio.datamodel import analyze_luau\nfrom roblox_studio.errors import ActivationError, BudgetError, ValidationError\nfrom roblox_studio.evidence_ledger import EvidenceLedger, EvidenceRecord\nfrom roblox_studio.memory import MemoryItem, ScopedMemory\nfrom roblox_studio.output_virtualization import virtualize_output\nfrom roblox_studio.profile import RobloxStudioOrchestrator\n\n\nclass ContextTests(unittest.TestCase):\n    def test_mandatory_roles_selected(self):\n        package=select_context(candidates(), required_roles=("definition","implementation"), token_budget=150)\n        self.assertEqual(set(package.covered_roles), {"definition","implementation"})\n        self.assertNotIn("noise", {item.candidate_id for item in package.selected})\n    def test_missing_role_fails(self):\n        with self.assertRaises(ValidationError): select_context(candidates(), required_roles=("validator",), token_budget=100)\n    def test_budget_pressure_fails_closed(self):\n        with self.assertRaises(BudgetError): select_context(candidates(), required_roles=("definition","implementation"), token_budget=100)\n    def test_stale_noise_loses(self):\n        package=select_context(candidates(), required_roles=("implementation",), token_budget=100)\n        self.assertEqual(package.selected[0].candidate_id, "impl")\n\n\nclass EvidenceTests(unittest.TestCase):\n    def record(self, evidence_id, branch="main", source_hash="a"):\n        now=int(time.time())\n        return EvidenceRecord(evidence_id,"task","script","ServerScriptService.Main",source_hash,"fp",branch,"c",1,now,"PROJECT","CLEAN","exact","summary",f"memory://{evidence_id}",now-1,now+60,None,("validator",))\n    def test_append_recover_and_chain(self):\n        with TemporaryDirectory() as temp:\n            ledger=EvidenceLedger(Path(temp)/"e.db"); ledger.append(self.record("e1"))\n            self.assertEqual(ledger.exact_recover("e1"), "exact"); self.assertTrue(ledger.verify_chain(project_fingerprint="fp", branch="main"))\n    def test_branch_isolation(self):\n        with TemporaryDirectory() as temp:\n            ledger=EvidenceLedger(Path(temp)/"e.db"); ledger.append(self.record("e1","main")); ledger.append(self.record("e2","feature"))\n            self.assertEqual(len(ledger.retrieve(project_fingerprint="fp", branch="main")),1)\n    def test_contradiction_detection(self):\n        with TemporaryDirectory() as temp:\n            ledger=EvidenceLedger(Path(temp)/"e.db")\n            contradictions=ledger.detect_contradictions((self.record("e1",source_hash="a"),self.record("e2",source_hash="b")))\n            self.assertEqual(len(contradictions),1)\n\n\nclass AdapterTests(unittest.TestCase):\n    def test_simulated_is_labeled(self):\n        response=SimulatedStudioAdapter().execute(EngineRequest("inspect_project","task",{}))\n        self.assertEqual(response.payload["mode"], "SIMULATED")\n    def test_transcript_order_validation(self):\n        with self.assertRaises(ValidationError): TranscriptAdapter((TranscriptEvent(1,"response",{}),))\n    def test_transcript_response(self):\n        adapter=TranscriptAdapter((TranscriptEvent(0,"response",{"capability":"inspect_project","status":"SUCCEEDED","evidence_references":["x"]}),))\n        self.assertEqual(adapter.execute(EngineRequest("inspect_project","task",{})).status,"SUCCEEDED")\n    def test_live_disabled(self):\n        with self.assertRaises(ActivationError): LiveStudioAdapter(enabled=False,session=None,transport=None).execute(EngineRequest("inspect_project","task",{}))\n\n\nclass LuauTests(unittest.TestCase):\n    def test_require_graph(self):\n        requires,_=analyze_luau("local x=require(script.Parent.X)")\n        self.assertEqual(requires,("script.Parent.X",))\n    def test_remote_validation_finding(self):\n        _,findings=analyze_luau("Remote.OnServerEvent:Connect(function(player, damage) end)")\n        self.assertIn("MISSING_SERVER_VALIDATION", {item.code for item in findings})\n    def test_loop_finding(self):\n        _,findings=analyze_luau("while true do print(\'x\') end")\n        self.assertIn("EXPENSIVE_LOOP", {item.code for item in findings})\n    def test_datastore_finding(self):\n        _,findings=analyze_luau("store:GetAsync(\'x\')")\n        self.assertIn("UNSAFE_DATASTORE", {item.code for item in findings})\n\n\nclass OutputMemoryTests(unittest.TestCase):\n    def test_output_preserves_marker_and_raw(self):\n        with TemporaryDirectory() as temp:\n            capsule=virtualize_output("ERROR boom\\nnoise\\nnoise\\n", storage_root=Path(temp), family="roblox")\n            self.assertIn("ERROR boom", capsule.critical_markers); self.assertEqual(capsule.duplicate_count,1); self.assertTrue(Path(capsule.raw_path).exists())\n    def test_memory_project_branch_commit_isolation(self):\n        with TemporaryDirectory() as temp:\n            store=ScopedMemory(Path(temp)/"m.db"); now=int(time.time())\n            store.put(MemoryItem("m","decision","fp","main","c1",("h",),now-1,now+60,1.0,None,"source_change","use sessions","PROJECT"))\n            self.assertEqual(len(store.query(project_fingerprint="fp",branch="main",commit="c1")),1)\n            self.assertEqual(len(store.query(project_fingerprint="other",branch="main",commit="c1")),0)\n            self.assertEqual(len(store.query(project_fingerprint="fp",branch="feature",commit="c1")),0)\n\n\nclass VerticalSliceTests(unittest.TestCase):\n    def test_signed_activation_to_verified_simulated_workflow_components(self):\n        with TemporaryDirectory() as temp:\n            orchestrator=RobloxStudioOrchestrator(Path(temp))\n            result=orchestrator.run(task(), candidates())\n            self.assertTrue(result.verified)\n            self.assertGreaterEqual(result.node_count,2)\n            self.assertTrue((Path(temp)/"checkpoint.json").exists())\n            self.assertTrue(orchestrator.ledger.verify_chain(project_fingerprint=task().project_fingerprint,branch="main"))\n            self.assertGreaterEqual(len(orchestrator.telemetry.replay(task().task_id)),2)\n\n\nif __name__ == "__main__": unittest.main()\n', 'tests/roblox_profile/test_scheduler_registry.py': 'from __future__ import annotations\n\nimport time\nimport unittest\n\nfrom _support import PROFILE_PARENT\nfrom roblox_studio.errors import CapabilityError\nfrom roblox_studio.registries import ModelRegistry, ModelSpec\nfrom roblox_studio.scheduler import select_route\n\n\ndef model(model_id, *, local=False, failure=0.01, latency=10, multimodal=False, privacy=True):\n    return ModelSpec(model_id,"local" if local else "provider",8192,True,multimodal,True,latency,failure,0.0 if local else 0.001,0.0 if local else 0.002,0.0,"test",int(time.time()),"HEALTHY",100,("code",),local)\n\n\nclass SchedulerTests(unittest.TestCase):\n    def test_deterministic_path(self):\n        decision=select_route(deterministic=True,privacy_class="PROJECT",task_family="code",registry=ModelRegistry([]))\n        self.assertEqual(decision.route,"DETERMINISTIC")\n    def test_local_only(self):\n        registry=ModelRegistry([model("cloud"),model("local",local=True,latency=30)])\n        self.assertEqual(select_route(deterministic=False,privacy_class="LOCAL_ONLY",task_family="code",registry=registry).model_id,"local")\n    def test_health_adjusted_selection(self):\n        registry=ModelRegistry([model("fast-bad",failure=.3,latency=1),model("safe",failure=.01,latency=20)])\n        self.assertEqual(select_route(deterministic=False,privacy_class="PROJECT",task_family="code",registry=registry).model_id,"safe")\n    def test_circuit_breaker(self):\n        registry=ModelRegistry([model("m")])\n        registry.record_failure("m"); registry.record_failure("m"); registry.record_failure("m")\n        with self.assertRaises(CapabilityError): select_route(deterministic=False,privacy_class="PROJECT",task_family="code",registry=registry)\n    def test_multimodal_requirement(self):\n        registry=ModelRegistry([model("text"),model("vision",multimodal=True,latency=20)])\n        self.assertEqual(select_route(deterministic=False,privacy_class="PROJECT",task_family="code",registry=registry,require_multimodal=True).model_id,"vision")\n    def test_stale_pricing(self):\n        item=model("cloud"); item.price_retrieved_at=0\n        self.assertTrue(item.pricing_is_stale(now=31*86400))\n\n\nif __name__ == "__main__": unittest.main()\n', 'tests/roblox_profile/test_task_capabilities.py': 'from __future__ import annotations\n\nimport unittest\nfrom dataclasses import replace\n\nfrom _support import task_mapping\nfrom roblox_studio.capabilities import default_capabilities\nfrom roblox_studio.capability_graph import CapabilityGraph\nfrom roblox_studio.errors import CapabilityError, SchemaError\nfrom roblox_studio.profile import VALIDATORS\nfrom roblox_studio.registries import default_engines\nfrom roblox_studio.task_state import RobloxTaskState, migrate_task_state\n\n\nclass TaskStateTests(unittest.TestCase):\n    def test_round_trip_and_hash(self):\n        state = RobloxTaskState.from_mapping(task_mapping())\n        self.assertEqual(RobloxTaskState.from_mapping(state.to_mapping()), state)\n        self.assertEqual(len(state.canonical_hash()), 64)\n\n    def test_unknown_field_rejected(self):\n        value=task_mapping(); value["unknown"] = True\n        with self.assertRaises(SchemaError): RobloxTaskState.from_mapping(value)\n\n    def test_requested_must_be_authorized(self):\n        with self.assertRaises(SchemaError): RobloxTaskState.from_mapping(task_mapping(requested_capabilities=["write_script"]))\n\n    def test_oversized_intent(self):\n        with self.assertRaises(SchemaError): RobloxTaskState.from_mapping(task_mapping(intent="x"*5000))\n\n    def test_negative_budget(self):\n        with self.assertRaises(SchemaError): RobloxTaskState.from_mapping(task_mapping(token_budget=-1))\n\n    def test_migrate_v1(self):\n        value=task_mapping(); value["schema_version"]=1; value.pop("project_id"); value.pop("privacy_class"); value.pop("gpu_budget"); value.pop("rollback_requirements")\n        migrated=migrate_task_state(value)\n        self.assertEqual(migrated["schema_version"], 2)\n        self.assertIn("project_id", migrated)\n\n\nclass CapabilityGraphTests(unittest.TestCase):\n    def setUp(self):\n        self.specs=default_capabilities(); self.engines=default_engines(self.specs)\n        self.graph=CapabilityGraph(self.specs, engines=self.engines.engines, validators=VALIDATORS)\n\n    def test_exactly_33_capabilities(self): self.assertEqual(len(self.specs), 33)\n    def test_plan_includes_dependencies(self):\n        plan=self.graph.plan(("write_script",), ("inspect_project","read_script","write_script"))\n        self.assertEqual(plan[-1], "write_script"); self.assertIn("inspect_project", plan)\n    def test_transitive_authorization_violation(self):\n        with self.assertRaises(CapabilityError): self.graph.plan(("write_script",), ("write_script",))\n    def test_unknown_capability(self):\n        with self.assertRaises(CapabilityError): self.graph.plan(("unknown",), ("unknown",))\n    def test_cycle_detected(self):\n        specs=dict(self.specs); specs["inspect_project"]=replace(specs["inspect_project"], dependencies=("write_script",))\n        with self.assertRaises(CapabilityError): CapabilityGraph(specs, engines=self.engines.engines, validators=VALIDATORS)\n    def test_unknown_validator_detected(self):\n        specs=dict(self.specs); specs["inspect_project"]=replace(specs["inspect_project"], required_validators=("missing",))\n        with self.assertRaises(CapabilityError): CapabilityGraph(specs, engines=self.engines.engines, validators=VALIDATORS)\n\n\nclass CapabilityCoverageTests(unittest.TestCase):\n    pass\n\n\ndef _positive(capability_id):\n    def test(self):\n        spec=default_capabilities()[capability_id]\n        self.assertTrue(spec.execution_contract)\n        self.assertTrue(spec.positive_test)\n        self.assertTrue(spec.negative_test)\n        self.assertTrue(spec.required_validators)\n        self.assertTrue(spec.engine_requirements)\n    return test\n\n\ndef _negative(capability_id):\n    def test(self):\n        specs=default_capabilities(); engines=default_engines(specs); graph=CapabilityGraph(specs, engines=engines.engines, validators=VALIDATORS)\n        with self.assertRaises(CapabilityError): graph.plan((capability_id,), ())\n    return test\n\nfor _capability_id in sorted(default_capabilities()):\n    setattr(CapabilityCoverageTests, f"test_{_capability_id}_positive", _positive(_capability_id))\n    setattr(CapabilityCoverageTests, f"test_{_capability_id}_negative", _negative(_capability_id))\n\n\nif __name__ == "__main__": unittest.main()\n', 'tools/run_roblox_tests.py': '#!/usr/bin/env python3\nfrom __future__ import annotations\n\nimport argparse\nimport json\nimport sys\nimport time\nimport unittest\nfrom pathlib import Path\n\nROOT = Path(__file__).resolve().parents[1]\n\n\ndef main() -> int:\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--output", required=True)\n    parser.add_argument("--source-commit", default="WORKTREE")\n    args = parser.parse_args()\n    loader = unittest.TestLoader()\n    suite = loader.discover(str(ROOT / "tests" / "roblox_profile"))\n    result = unittest.TestResult()\n    started = time.perf_counter()\n    suite.run(result)\n    payload = {\n        "source_commit": args.source_commit,\n        "tests_run": result.testsRun,\n        "failures": len(result.failures),\n        "errors": len(result.errors),\n        "skipped": len(result.skipped),\n        "duration_ms": (time.perf_counter() - started) * 1000,\n        "status": "PASS" if result.wasSuccessful() else "FAIL",\n        "maturity": "INTERNALLY_VERIFIED",\n    }\n    output = Path(args.output)\n    output.parent.mkdir(parents=True, exist_ok=True)\n    output.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")\n    print(json.dumps(payload, indent=2, sort_keys=True))\n    return 0 if result.wasSuccessful() else 2\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n'}
for relative, content in FILES.items():
    path=Path(relative)
